const FadeIn = ({ children, delay = 0, duration = 0.7, x = 0, y = 0, style = {}, className = "" }) => (
  <motion.div
    className={className}
    style={style}
    initial={{ opacity: 0, x, y }}
    whileInView={{ opacity: 1, x: 0, y: 0 }}
    viewport={{ once: true, margin: "50px", amount: 0 }}
    transition={{ duration, delay, ease: [0.22, 1, 0.36, 1] }}
  >
    {children}
  </motion.div>
);

const Magnet = ({ children, padding = 150, strength = 3 }) => {
  const ref = useRef(null);
  const [pos, setPos] = useState({ x: 0, y: 0 });
  const [active, setActive] = useState(false);
  const handleMouseMove = useCallback((e) => {
    if (!ref.current) return;
    const rect = ref.current.getBoundingClientRect();
    const cx = rect.left + rect.width / 2;
    const cy = rect.top + rect.height / 2;
    const dx = e.clientX - cx;
    const dy = e.clientY - cy;
    const dist = Math.sqrt(dx * dx + dy * dy);
    if (dist < rect.width / 2 + padding) {
      setPos({ x: (dx / dist) * Math.min(dist, 30) * (strength / 3), y: (dy / dist) * Math.min(dist, 30) * (strength / 3) });
      setActive(true);
    } else { setPos({ x: 0, y: 0 }); setActive(false); }
  }, [padding, strength]);
  useEffect(() => {
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, [handleMouseMove]);
  return (
    <div ref={ref} style={{ transform: `translate(${pos.x}px, ${pos.y}px)`, transition: active ? "transform 0.3s ease-out" : "transform 0.6s ease-in-out", display: "inline-block" }}>
      {children}
    </div>
  );
};

