const AnimatedText = ({ text, style = {} }) => {
  const ref = useRef(null);
  const { scrollYProgress } = useScroll({ target: ref, offset: ["start 0.9", "end 0.3"] });
  const chars = text.split("");
  return (
    <p ref={ref} style={style}>
      {chars.map((char, i) => {
        const start = i / chars.length;
        const end = (i + 1) / chars.length;
        return <AnimChar key={i} char={char} progress={scrollYProgress} start={start} end={end} />;
      })}
    </p>
  );
};
const AnimChar = ({ char, progress, start, end }) => {
  const opacity = useTransform(progress, [start, end], [0.15, 1]);
  return <motion.span style={{ opacity, display: "inline" }}>{char}</motion.span>;
};

