const MarqueeSection = () => {
  const ref = useRef(null);
  const [offset, setOffset] = useState(0);
  useEffect(() => {
    const fn = () => {
      if (!ref.current) return;
      const rect = ref.current.getBoundingClientRect();
      const sTop = window.scrollY + rect.top;
      setOffset((window.scrollY - sTop + window.innerHeight) * 0.3);
    };
    window.addEventListener("scroll", fn, { passive: true });
    fn();
    return () => window.removeEventListener("scroll", fn);
  }, []);
  const r1 = [...marqueeItems.slice(0, 11), ...marqueeItems.slice(0, 11), ...marqueeItems.slice(0, 11)];
  const r2 = [...marqueeItems.slice(11), ...marqueeItems.slice(11), ...marqueeItems.slice(11)];
  return (
    <section ref={ref} style={{ background: "#0C0C0C", padding: "160px 0 40px", overflow: "hidden" }}>
      <div style={{ display: "flex", flexDirection: "column", gap: "12px" }}>
        <div style={{ display: "flex", gap: "12px", willChange: "transform", transform: `translateX(${-offset}px)` }}>{r1.map((item, i) => <MCard key={i} item={item} />)}</div>
        <div style={{ display: "flex", gap: "12px", willChange: "transform", transform: `translateX(${offset - 600}px)` }}>{r2.map((item, i) => <MCard key={i} item={item} />)}</div>
      </div>
    </section>
  );
};

