const PCard = ({ project, index }) => {
  const ref = useRef(null);
  const { scrollYProgress } = useScroll({ target: ref, offset: ["start end", "end start"] });
  const scale = useTransform(scrollYProgress, [0, 0.5, 1], [0.95, 1, 0.97]);
  const y = useTransform(scrollYProgress, [0, 1], [0, -30]);
  return (
    <motion.div ref={ref} style={{ scale, y, position: "sticky", top: `${80 + index * 24}px`, zIndex: 10 + index }}>
      <div style={{ background: project.color, border: `1px solid ${project.accent}30`, borderRadius: "32px", padding: "clamp(32px, 5vw, 64px)", display: "flex", flexDirection: "column", gap: "24px", minHeight: "380px", position: "relative", overflow: "hidden" }}>
        <div style={{ position: "absolute", top: "-80px", right: "-80px", width: "320px", height: "320px", borderRadius: "50%", background: `radial-gradient(circle, ${project.accent}20 0%, transparent 70%)` }} />
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
          <div>
            <span style={{ fontFamily: "Kanit, sans-serif", color: project.accent, fontSize: "0.75rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.2em" }}>{project.cat}</span>
            <h3 style={{ fontFamily: "Kanit, sans-serif", fontWeight: 900, fontSize: "clamp(1.8rem, 4vw, 3.5rem)", color: "#fff", textTransform: "uppercase", letterSpacing: "-0.02em", marginTop: "4px", lineHeight: 1 }}>{project.title}</h3>
          </div>
          <span style={{ fontSize: "56px" }}>{project.emoji}</span>
        </div>
        <p style={{ fontFamily: "Kanit, sans-serif", fontWeight: 300, fontSize: "clamp(0.9rem, 1.5vw, 1.1rem)", color: "rgba(215,226,234,0.75)", maxWidth: "520px", lineHeight: 1.6 }}>{project.desc}</p>
      </div>
    </motion.div>
  );
};
